import torch
import torch.nn as nn
import torch.nn.functional as F


class kan_coord_head_unet(nn.Module):
    class _ConvBlock(nn.Module):
        def __init__(self, in_ch, out_ch):
            super().__init__()
            self.net = nn.Sequential(
                nn.ReflectionPad2d(1),
                nn.Conv2d(in_ch, out_ch, kernel_size=3, bias=False),
                nn.GroupNorm(self._groups(out_ch), out_ch),
                nn.SiLU(inplace=True),
                nn.ReflectionPad2d(1),
                nn.Conv2d(out_ch, out_ch, kernel_size=3, bias=False),
                nn.GroupNorm(self._groups(out_ch), out_ch),
                nn.SiLU(inplace=True),
            )

        @staticmethod
        def _groups(ch):
            for g in (8, 6, 4, 3, 2, 1):
                if ch % g == 0:
                    return g
            return 1

        def forward(self, x):
            return self.net(x)

    class _UpBlock(nn.Module):
        def __init__(self, in_ch, skip_ch, out_ch):
            super().__init__()
            self.reduce = nn.Conv2d(in_ch, out_ch, kernel_size=1, bias=False)
            self.block = kan_coord_head_unet._ConvBlock(out_ch + skip_ch, out_ch)

        def forward(self, x, skip):
            x = F.interpolate(x, size=skip.shape[-2:], mode="bilinear", align_corners=False)
            x = self.reduce(x)
            x = torch.cat([x, skip], dim=1)
            return self.block(x)

    class _KANCoordHead(nn.Module):
        def __init__(self, in_ch, out_ch, hidden_ch):
            super().__init__()
            self.fc1 = nn.Conv2d(in_ch + 2, hidden_ch, kernel_size=1)
            self.fc2 = nn.Conv2d(hidden_ch * 3, hidden_ch, kernel_size=1)
            self.fc3 = nn.Conv2d(hidden_ch, out_ch, kernel_size=1)

        def forward(self, x):
            b, _, h, w = x.shape
            yy = torch.linspace(-1.0, 1.0, h, device=x.device, dtype=x.dtype).view(1, 1, h, 1).expand(b, 1, h, w)
            xx = torch.linspace(-1.0, 1.0, w, device=x.device, dtype=x.dtype).view(1, 1, 1, w).expand(b, 1, h, w)
            x = torch.cat([x, xx, yy], dim=1)

            z = self.fc1(x)
            z = torch.cat([F.silu(z), torch.sin(z), z * torch.sigmoid(z)], dim=1)
            z = F.silu(self.fc2(z))
            return self.fc3(z)

    def __init__(self, in_channels=1, out_channels=1, n_c=16, depth=7):
        super().__init__()
        if depth < 1:
            raise ValueError("depth must be >= 1")

        channels = [min(n_c * (2 ** i), n_c * 8) for i in range(depth)]

        self.encoders = nn.ModuleList()
        prev_ch = in_channels
        for ch in channels:
            self.encoders.append(self._ConvBlock(prev_ch, ch))
            prev_ch = ch

        self.bottleneck = self._ConvBlock(channels[-1], channels[-1])

        self.decoders = nn.ModuleList()
        for i in range(depth - 2, -1, -1):
            self.decoders.append(self._UpBlock(prev_ch, channels[i], channels[i]))
            prev_ch = channels[i]

        self.head = self._KANCoordHead(prev_ch, out_channels, max(n_c, channels[0]))

    def forward(self, x):
        valid = ~torch.isnan(x)
        x_masked = torch.where(valid, x, torch.zeros_like(x))

        skips = []
        y = x_masked
        for i, encoder in enumerate(self.encoders):
            y = encoder(y)
            skips.append(y)
            if i < len(self.encoders) - 1:
                y = F.avg_pool2d(y, kernel_size=2, stride=2)

        y = self.bottleneck(y)

        for decoder, skip in zip(self.decoders, reversed(skips[:-1])):
            y = decoder(y, skip)

        y = self.head(y)
        valid_out = valid.all(dim=1, keepdim=True)
        y = torch.where(valid_out, y, torch.full_like(y, float("nan")))
        return y
